def rollback_last(self) -> str:
    """Rollback the most recently applied migration."""
    if not self.applied:
        raise ValueError('No migrations to rollback')
    last_name = self.applied[-1]
    for m in reversed(self.migrations):
        if m.__class__.__name__ == last_name:
            result = m.down()
            self.applied.pop()
            return result
    raise ValueError(f'Migration {last_name} not found')
